      W = innerWidth; H = innerHeight;
      Object.values(layers).forEach(({c,ctx}) => { c.width = W*DPR; c.height = H*DPR; c.style.width = W+'px'; c.style.height = H+'px'; ctx.setTransform(DPR,0,0,DPR,0,0); });
      stars = Array.from({length: Math.floor(W*H/5200)}, () => ({x:Math.random()*W,y:Math.random()*H,r:Math.random()*1.4+.25,a:Math.random(),s:Math.random()*.35+.06}));
      petals = Array.from({length: 20}, () => ({x:Math.random()*W,y:Math.random()*H,vx:Math.random()*.45+.12,vy:Math.random()*.23+.07,rot:Math.random()*6.28,vr:(Math.random()-.5)*.018,size:Math.random()*14+8}));
      dust = [];
    }
    addEventListener('resize', resize); resize();
    addEventListener('pointermove', e => { for(let i=0;i<3;i++) dust.push({x:e.clientX,y:e.clientY,vx:(Math.random()-.5)*1.8,vy:(Math.random()-.5)*1.8,r:Math.random()*2+1,life:80}); if(dust.length>130) dust.splice(0,dust.length-130); });
    function draw(t){
      let ctx = layers.stars.ctx; ctx.clearRect(0,0,W,H);
      stars.forEach(s => { const a=.22+(Math.sin(t*.001*s.s+s.a*9)+1)*.26; ctx.beginPath(); ctx.fillStyle=`rgba(255,249,220,${a})`; ctx.arc(s.x,s.y,s.r,0,6.28); ctx.fill(); });
      ctx = layers.petals.ctx; ctx.clearRect(0,0,W,H);
      petals.forEach(p => { p.x+=p.vx+Math.sin(p.y*.01)*.18; p.y+=p.vy; p.rot+=p.vr; if(p.x>W+40)p.x=-40; if(p.y>H+40)p.y=-40; ctx.save(); ctx.translate(p.x,p.y); ctx.rotate(p.rot); ctx.scale(1,.55); const g=ctx.createRadialGradient(0,0,1,0,0,p.size); g.addColorStop(0,'rgba(255,238,232,.62)'); g.addColorStop(.55,'rgba(169,61,86,.45)'); g.addColorStop(1,'rgba(120,38,52,.05)'); ctx.fillStyle=g; ctx.beginPath(); ctx.ellipse(0,0,p.size,p.size*.72,0,0,6.28); ctx.fill(); ctx.restore(); });
      ctx = layers.dust.ctx; ctx.clearRect(0,0,W,H);
      dust.forEach(d => { d.x+=d.vx; d.y+=d.vy; d.life--; const a=Math.max(d.life/80,0); ctx.beginPath(); ctx.fillStyle=`rgba(255,250,220,${a*.42})`; ctx.arc(d.x,d.y,d.r,0,6.28); ctx.fill(); });
      dust = dust.filter(d => d.life>0);
      requestAnimationFrame(draw);
    }
    requestAnimationFrame(draw);
  </script>
